ALTER TABLE proposal_comments ADD COLUMN `userId` int NOT NULL DEFAULT 0;
UPDATE proposal_comments SET `userId` = `authorId`;
ALTER TABLE proposal_comments DROP COLUMN `authorId`;
ALTER TABLE proposal_comments DROP COLUMN `updatedAt`;

-- Fix notifications: fix 'type' to varchar, fix 'message' to nullable, add 'title' length
ALTER TABLE notifications MODIFY COLUMN `type` varchar(64) NOT NULL;
ALTER TABLE notifications MODIFY COLUMN `title` varchar(256) NOT NULL;
ALTER TABLE notifications MODIFY COLUMN `message` text;
ALTER TABLE notifications MODIFY COLUMN `link` varchar(512);

